#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    ll n,k;    cin >> n >> k;        vll a(n*k);    for(int i=0; i<n*k; i++) cin >> a[i];    ll sum=0;    ll i=n*k;    while(k--){    i -=(n/2+1);    sum+=a[i];   }    cout << sum << "\n";}  // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}